from dataclasses import dataclass
from typing import List

@dataclass
class FunctionDescriptor:
    name: str
    parameters: List[str]

def evaluate_function(descriptor: FunctionDescriptor, args: List[str]) -> str:
    if descriptor.name == "concat":
        return "".join(args)
    elif descriptor.name == "sum":
        return str(sum(map(int, args)))
    else:
        raise ValueError("Unknown function")

def main():
    concat_descriptor = FunctionDescriptor(name="concat", parameters=["arg1", "arg2"])
    sum_descriptor = FunctionDescriptor(name="sum", parameters=["arg1", "arg2"])

    result_concat = evaluate_function(concat_descriptor, ["Hello", "World"])
    print(result_concat)

    result_sum = evaluate_function(sum_descriptor, ["1", "2"])
    print(result_sum)

if __name__ == "__main__":
    main()
